import{_ as h,C as e,c as d,o as u,ag as r,G as t,w as i,j as a,a as l}from"./chunks/framework.dvv-DFtf.js";const F=JSON.parse('{"title":"Webmail 常见问题","description":"","frontmatter":{},"headers":[],"relativePath":"webmail/faq.md","filePath":"webmail/faq.md","lastUpdated":null}'),p={name:"webmail/faq.md"};function c(k,s,g,b,m,q){const n=e("PluginTabsTab"),o=e("PluginTabs");return u(),d("div",null,[s[4]||(s[4]=r('<div style="display:none;" hidden="true" aria-hidden="true">Are you an LLM? You can read better optimized documentation at /webmail\\faq.md for this page in Markdown format</div><h1 id="webmail-常见问题" tabindex="-1">Webmail 常见问题 <a class="header-anchor" href="#webmail-常见问题" aria-label="Permalink to &quot;Webmail 常见问题&quot;">​</a></h1><h2 id="登录问题" tabindex="-1">登录问题 <a class="header-anchor" href="#登录问题" aria-label="Permalink to &quot;登录问题&quot;">​</a></h2><h3 id="忘记密码怎么办" tabindex="-1">忘记密码怎么办？ <a class="header-anchor" href="#忘记密码怎么办" aria-label="Permalink to &quot;忘记密码怎么办？&quot;">​</a></h3><p>联系管理员重置：admin@lurus.cn，说明你的邮箱地址即可。重置后会收到临时密码邮件，<strong>请在 24 小时内登录并修改</strong>。</p><h3 id="账号被锁定了" tabindex="-1">账号被锁定了？ <a class="header-anchor" href="#账号被锁定了" aria-label="Permalink to &quot;账号被锁定了？&quot;">​</a></h3><p>连续 5 次密码错误会触发 15 分钟锁定，等待后自动解除。紧急情况联系管理员手动解锁。</p><h3 id="web-界面无法访问" tabindex="-1">Web 界面无法访问？ <a class="header-anchor" href="#web-界面无法访问" aria-label="Permalink to &quot;Web 界面无法访问？&quot;">​</a></h3><ol><li>确认网络可以访问 <a href="https://mail.lurus.cn" target="_blank" rel="noreferrer">mail.lurus.cn</a></li><li>清除浏览器缓存（<code>Ctrl+Shift+Del</code>）或尝试无痕模式</li><li>若仍无法访问，联系 <a href="mailto:support@lurus.cn" target="_blank" rel="noreferrer">support@lurus.cn</a></li></ol><hr><h2 id="发送问题" tabindex="-1">发送问题 <a class="header-anchor" href="#发送问题" aria-label="Permalink to &quot;发送问题&quot;">​</a></h2><h3 id="给-qq-163-126-邮箱发邮件对方收不到" tabindex="-1">给 QQ / 163 / 126 邮箱发邮件对方收不到？ <a class="header-anchor" href="#给-qq-163-126-邮箱发邮件对方收不到" aria-label="Permalink to &quot;给 QQ / 163 / 126 邮箱发邮件对方收不到？&quot;">​</a></h3><p>国内主流邮箱通过 SendCloud 中继发送，偶有延迟。请按以下顺序排查：</p><p><strong>第一步：让对方检查垃圾邮件文件夹</strong>，大多数情况问题到此解决。</p><p><strong>第二步：让对方将 <code>@lurus.cn</code> 加入白名单：</strong></p>',15)),t(o,null,{default:i(()=>[t(n,{label:"QQ 邮箱"},{default:i(()=>[...s[0]||(s[0]=[a("ol",null,[a("li",null,[l("登录 QQ 邮箱 → "),a("strong",null,"设置"),l(" → "),a("strong",null,"反垃圾")]),a("li",null,[l("点击「"),a("strong",null,"添加白名单"),l("」→ 输入 "),a("code",null,"@lurus.cn")]),a("li",null,"点击保存")],-1)])]),_:1}),t(n,{label:"163 / 126 邮箱"},{default:i(()=>[...s[1]||(s[1]=[a("ol",null,[a("li",null,[l("登录 → "),a("strong",null,"设置"),l(" → "),a("strong",null,"反垃圾/黑白名单")]),a("li",null,[l("选择「"),a("strong",null,"白名单"),l("」→「"),a("strong",null,"添加白名单"),l("」")]),a("li",null,[l("输入 "),a("code",null,"lurus.cn"),l("，选择「域名」类型，保存")])],-1)])]),_:1}),t(n,{label:"Outlook / Hotmail"},{default:i(()=>[...s[2]||(s[2]=[a("ol",null,[a("li",null,[l("登录 Outlook.com → "),a("strong",null,"设置"),l("（⚙️）→ "),a("strong",null,"垃圾邮件")]),a("li",null,[l("「"),a("strong",null,"安全发件人和域"),l("」→「"),a("strong",null,"添加"),l("」")]),a("li",null,[l("输入 "),a("code",null,"lurus.cn"),l("，点击保存")])],-1)])]),_:1}),t(n,{label:"Gmail"},{default:i(()=>[...s[3]||(s[3]=[a("ol",null,[a("li",null,[l("打开该邮件 → 右上角「⋮」→「"),a("strong",null,"筛选此类邮件"),l("」")]),a("li",null,[l("点击「"),a("strong",null,"创建过滤条件"),l("」→ 勾选「"),a("strong",null,"永不发送到垃圾邮件"),l("」")]),a("li",null,"点击保存")],-1)])]),_:1})]),_:1}),s[5]||(s[5]=r(`<p><strong>第三步：</strong> 等待 5–10 分钟后重试。若仍未送达，联系 <a href="mailto:support@lurus.cn" target="_blank" rel="noreferrer">support@lurus.cn</a> 并提供：收件方邮箱域名 + 发送时间。</p><h3 id="发邮件报错-relay-denied" tabindex="-1">发邮件报错 &quot;Relay denied&quot;？ <a class="header-anchor" href="#发邮件报错-relay-denied" aria-label="Permalink to &quot;发邮件报错 &quot;Relay denied&quot;？&quot;">​</a></h3><p>原因：SMTP 认证失败。检查：</p><ul><li>用户名必须是<strong>完整邮箱地址</strong>（如 <code>zhangsan@lurus.cn</code>，不能只写 <code>zhangsan</code>）</li><li>密码是否正确（区分大小写）</li><li>端口和加密是否匹配（推荐 <code>587</code> / STARTTLS）</li></ul><h3 id="附件发送失败" tabindex="-1">附件发送失败？ <a class="header-anchor" href="#附件发送失败" aria-label="Permalink to &quot;附件发送失败？&quot;">​</a></h3><ul><li>单封邮件附件上限 <strong>25 MB</strong>，超过请改用网盘分享链接</li><li>附件文件名避免特殊字符（<code>* / \\ : ? &quot; &lt; &gt; |</code>）</li></ul><h3 id="邮件被对方标为垃圾邮件" tabindex="-1">邮件被对方标为垃圾邮件？ <a class="header-anchor" href="#邮件被对方标为垃圾邮件" aria-label="Permalink to &quot;邮件被对方标为垃圾邮件？&quot;">​</a></h3><p>我们已配置 SPF / DKIM / DMARC。如果仍被拦截，可以自行验证邮件的认证状态：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 查看邮件头部的认证结果（在对方那里查看原始邮件头）</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 正常情况应看到：</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">Authentication-Results:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> mx.google.com</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">   dkim</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">pass</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> header.d</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">=lurus.cn</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">   spf</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">pass</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> smtp.mailfrom</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">=lurus.cn</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">   dmarc</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">pass</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 或用命令行验证 DNS 记录</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">dig</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> TXT</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> lurus.cn</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> grep</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> spf</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 应返回：v=spf1 include:sendcloud.net ~all</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">dig</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> TXT</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> mail._domainkey.lurus.cn</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 应返回 DKIM 公钥（v=DKIM1; k=rsa; p=...）</span></span></code></pre></div><p>如果上述记录异常，联系 <a href="mailto:support@lurus.cn" target="_blank" rel="noreferrer">support@lurus.cn</a> 提供完整邮件头信息。</p><hr><h2 id="接收问题" tabindex="-1">接收问题 <a class="header-anchor" href="#接收问题" aria-label="Permalink to &quot;接收问题&quot;">​</a></h2><h3 id="客户端收不到新邮件" tabindex="-1">客户端收不到新邮件？ <a class="header-anchor" href="#客户端收不到新邮件" aria-label="Permalink to &quot;客户端收不到新邮件？&quot;">​</a></h3><ol><li>确认 IMAP 连接参数正确：服务器 <code>mail.lurus.cn</code>，端口 <code>993</code>，SSL/TLS</li><li>手动触发「检查邮件」或「刷新」</li><li>检查邮件是否被过滤规则移到其他文件夹</li></ol><h3 id="邮件跑到垃圾箱了" tabindex="-1">邮件跑到垃圾箱了？ <a class="header-anchor" href="#邮件跑到垃圾箱了" aria-label="Permalink to &quot;邮件跑到垃圾箱了？&quot;">​</a></h3><ol><li>打开垃圾邮件文件夹，找到该邮件</li><li>点击「<strong>标记为非垃圾邮件</strong>」</li><li>将发件人加入白名单：「<strong>设置</strong>」→「<strong>白名单</strong>」→「<strong>添加发件人</strong>」</li></ol><hr><h2 id="客户端配置问题" tabindex="-1">客户端配置问题 <a class="header-anchor" href="#客户端配置问题" aria-label="Permalink to &quot;客户端配置问题&quot;">​</a></h2><h3 id="outlook-报错-无法连接到服务器" tabindex="-1">Outlook 报错&quot;无法连接到服务器&quot;？ <a class="header-anchor" href="#outlook-报错-无法连接到服务器" aria-label="Permalink to &quot;Outlook 报错&quot;无法连接到服务器&quot;？&quot;">​</a></h3><p>请严格按以下参数配置：</p><table tabindex="0"><thead><tr><th>类型</th><th>服务器</th><th>端口</th><th>加密</th></tr></thead><tbody><tr><td>IMAP（收件）</td><td>mail.lurus.cn</td><td>993</td><td>SSL/TLS</td></tr><tr><td>SMTP（发件）</td><td>mail.lurus.cn</td><td>587</td><td>STARTTLS</td></tr></tbody></table><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>用户名必须填写<strong>完整邮箱地址</strong>，包含 <code>@lurus.cn</code>。部分客户端默认只填用户名前缀会导致认证失败。</p></div><h3 id="iphone-配置后发件显示失败" tabindex="-1">iPhone 配置后发件显示失败？ <a class="header-anchor" href="#iphone-配置后发件显示失败" aria-label="Permalink to &quot;iPhone 配置后发件显示失败？&quot;">​</a></h3><p>iOS 邮件 App 有时对 STARTTLS（587 端口）有兼容性问题。改用 SMTP 端口 <code>465</code> + <code>SSL/TLS</code> 加密通常可以解决。</p><h3 id="thunderbird-提示证书错误" tabindex="-1">Thunderbird 提示证书错误？ <a class="header-anchor" href="#thunderbird-提示证书错误" aria-label="Permalink to &quot;Thunderbird 提示证书错误？&quot;">​</a></h3><ol><li>检查系统时间是否准确（证书验证依赖系统时间，误差超过 5 分钟会报错）</li><li>删除现有账户重新添加</li><li>若出现「证书不受信任」提示，检查证书颁发机构是否为 Let&#39;s Encrypt，选择「永久信任」</li></ol><hr><h2 id="存储与配额" tabindex="-1">存储与配额 <a class="header-anchor" href="#存储与配额" aria-label="Permalink to &quot;存储与配额&quot;">​</a></h2><h3 id="邮箱存储配额是多少" tabindex="-1">邮箱存储配额是多少？ <a class="header-anchor" href="#邮箱存储配额是多少" aria-label="Permalink to &quot;邮箱存储配额是多少？&quot;">​</a></h3><p>默认每个账号 <strong>10 GB</strong>。查看已用空间：Web 界面右下角，或「<strong>设置</strong>」→「<strong>账户信息</strong>」。</p><h3 id="如何清理空间" tabindex="-1">如何清理空间？ <a class="header-anchor" href="#如何清理空间" aria-label="Permalink to &quot;如何清理空间？&quot;">​</a></h3><table tabindex="0"><thead><tr><th>操作</th><th>节省空间</th></tr></thead><tbody><tr><td>清空垃圾箱和垃圾邮件</td><td>通常可释放 30–50%</td></tr><tr><td>删除含大附件的旧邮件</td><td>过滤「附件大于 5 MB」搜索定位</td></tr><tr><td>清空「已发送」中的大附件邮件</td><td>已发送通常占用最多空间</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">快速搜索大附件</p><p>在搜索框输入 <code>has:attachment larger:5MB</code> 可快速定位大邮件。</p></div><h3 id="配额不够怎么申请扩容" tabindex="-1">配额不够怎么申请扩容？ <a class="header-anchor" href="#配额不够怎么申请扩容" aria-label="Permalink to &quot;配额不够怎么申请扩容？&quot;">​</a></h3><p>联系管理员（admin@lurus.cn）申请，说明你的邮箱地址和需要的容量。</p><hr><h2 id="安全" tabindex="-1">安全 <a class="header-anchor" href="#安全" aria-label="Permalink to &quot;安全&quot;">​</a></h2><h3 id="如何开启两步验证" tabindex="-1">如何开启两步验证？ <a class="header-anchor" href="#如何开启两步验证" aria-label="Permalink to &quot;如何开启两步验证？&quot;">​</a></h3><p>Webmail 通过 Zitadel 统一认证，在 <a href="https://auth.lurus.cn" target="_blank" rel="noreferrer">auth.lurus.cn</a> → <strong>账号安全</strong> 中开启 TOTP（推荐 Google Authenticator 或 1Password）。</p><h3 id="如何查看登录记录" tabindex="-1">如何查看登录记录？ <a class="header-anchor" href="#如何查看登录记录" aria-label="Permalink to &quot;如何查看登录记录？&quot;">​</a></h3><p>「<strong>设置</strong>」→「<strong>安全</strong>」→「<strong>登录历史</strong>」，查看近 30 天的登录 IP 和时间。</p><div class="danger custom-block"><p class="custom-block-title">发现异常登录</p><p>立即：① 修改密码 ② 撤销所有其他登录会话 ③ 联系 <a href="mailto:admin@lurus.cn" target="_blank" rel="noreferrer">admin@lurus.cn</a> 报告异常 IP</p></div>`,42))])}const y=h(p,[["render",c]]);export{F as __pageData,y as default};
